// ==========================================
// academicDB.js — Enriched Academic Database
//
// Source: generated by generate_db.py
// Contains 538+ words with 4 fields each:
//   word, translation, pos, level
//
// Usage:
//   import { lookup, lookupFull } from './academicDB';
//
//   lookup('resilient')
//   → { translation: 'עמיד, חסין', pos: 'Adjective', level: 3, inDatabase: true }
//
//   lookupFull({ minLevel: 2, pos: 'Verb' })
//   → [ all level 2+ verbs ... ]
// ==========================================

import rawData from './academicDB.json';

// Build O(1) lookup map on module load (runs once, no cost at query time)
const _map = Object.create(null);
for (const entry of rawData) {
  _map[entry.word.toLowerCase()] = entry;
}

/**
 * lookup(word) — find a word in the enriched database.
 *
 * Returns null if not found (so the caller can fall back to
 * the legacy psychometricDB or an online API).
 *
 * @param {string} word
 * @returns {{ translation: string, pos: string, level: number, inDatabase: true } | null}
 */
export const lookup = (word) => {
  const entry = _map[word.trim().toLowerCase()];
  if (!entry) return null;
  return {
    translation: entry.translation,
    pos:         entry.pos,
    level:       entry.level,
    inDatabase:  true,
  };
};

/**
 * lookupFull(filters?) — return all entries, optionally filtered.
 *
 * @param {{ minLevel?: number, maxLevel?: number, pos?: string }} [filters]
 * @returns {Array}
 */
export const lookupFull = (filters = {}) => {
  let entries = rawData;
  if (filters.minLevel) entries = entries.filter(e => e.level >= filters.minLevel);
  if (filters.maxLevel) entries = entries.filter(e => e.level <= filters.maxLevel);
  if (filters.pos)      entries = entries.filter(e => e.pos === filters.pos);
  return entries;
};

/** Total number of words in the database */
export const dbSize = rawData.length;

export default _map;
